create table if not exists sys_soft_delete_records (id uuid primary key, tenant_id varchar(64) not null default 'default', entity_type varchar(80) not null, entity_id uuid not null, title varchar(240) not null, status varchar(32) not null default 'PENDING', requested_by varchar(120), requested_role_codes varchar(500), requested_at timestamp with time zone not null default current_timestamp, approval_id uuid, approved_by varchar(120), approved_at timestamp with time zone, restored_by varchar(120), restored_at timestamp with time zone, created_at timestamp with time zone not null default current_timestamp, updated_at timestamp with time zone not null default current_timestamp);
create index if not exists idx_soft_delete_entity on sys_soft_delete_records(entity_type,entity_id,status);
create index if not exists idx_soft_delete_status on sys_soft_delete_records(status,requested_at);
insert into sys_permissions (id,tenant_id,code,name,module,built_in,created_at,updated_at) select '00000000-0000-4000-8000-000000002105','default','system:deleted-records:manage','删除回收站管理','system',true,current_timestamp,current_timestamp where not exists(select 1 from sys_permissions where tenant_id='default' and code='system:deleted-records:manage');
